INSERT INTO VX_CustomerTag (id, externalUserid, userid, tagId, tagName, source, batchNo, createTime) SELECT item.id, item.externalUserid, item.userid, item.tagId, item.tagName, item.source, item.batchNo, GETDATE() FROM ( VALUES
(#{item.id}, #{item.externalUserid}, #{item.userid}, #{item.tagId}, #{item.tagName}, #{item.source}, #{item.batchNo})
) AS item(id, externalUserid, userid, tagId, tagName, source, batchNo) WHERE NOT EXISTS ( SELECT 1 FROM VX_CustomerTag t WHERE t.externalUserid = item.externalUserid AND t.userid = item.userid AND t.tagId = item.tagId )
